INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('elementary-10ced7e2-moex-00691', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-111-01c5eaab', 'sub-elementary-10ced7e2-05', NULL, 'single_choice', '下列各項競賽獎牌上的題辭，使用正確的選項是：', '["作文：錦心繡口", "書法：鞭辟入裡", "演說：翰苑之光", "音樂：含英咀華"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:47+00:00", "source_pdf_sha1": "6590d4ee65e2", "answer_pdf_sha1": "e24c36da3da8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "506", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00692', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-111-01c5eaab', 'sub-elementary-10ced7e2-05', NULL, 'single_choice', '「這些機器不是阿公以前工廠裡的織布機，但機器運轉的聲音十分相似，那聲音幾乎要讓我以為， 阿公就在這裡，只要我願意等，他就會從樓上走下來。想到這裡，我趕緊走到屋外，深吸一口氣， 緩和情緒，怕自己在不熟識的人面前，忍不住哭了出來。」 上文主要是描述什麼情感？', '["對不熟識人的害羞", "對親人的幻覺想像", "對阿公的思念之情", "對個人情緒的控制"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:47+00:00", "source_pdf_sha1": "6590d4ee65e2", "answer_pdf_sha1": "e24c36da3da8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "506", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00693', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-111-01c5eaab', 'sub-elementary-10ced7e2-05', NULL, 'single_choice', '「一國的民族文化能否保持活力，仰賴的無非是與其他文化互動，畢竟專業知能與創造力都奠基於 不同類型的知識與觀點的對話及互補。」依此觀點，下列何種政策對增進民族文化的活力最無效益？', '["健全發展交換學生制度", "加強促進跨國科技研發", "立法獎勵國際人才移動", "嚴格規定交流學者資格"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:47+00:00", "source_pdf_sha1": "6590d4ee65e2", "answer_pdf_sha1": "e24c36da3da8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "506", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00694', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-111-01c5eaab', 'sub-elementary-10ced7e2-05', NULL, 'single_choice', '「說胰臟像尺，其實有些勉強。它可是有頭有身，甚至尾巴的器官。這身型別致的臟器，我總覺得 不像尺，而像個逗點，像隻蝌蚪，或像枚水滴。它是跨領域的，擁雙專長：屬消化系，亦屬內分泌 系；能分泌胰液，分解食物，亦能製造多項荷爾蒙，調控血糖平衡。胰臟似乎帶有一種『分泌』的 宿命，終其一生都在榨出。在超音波底下，只要胃腸氣多了，胰臟能見度就差了，這和肝膽脾腎不 太一樣。它習慣深藏，習慣若隱若現，在臟腑中最具隱士情操。」 上文的敘述，沒有從那個角度描寫胰臟？', '["形狀聯想", "臟器功能", "養生方法", "象徵想像"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:47+00:00", "source_pdf_sha1": "6590d4ee65e2", "answer_pdf_sha1": "e24c36da3da8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "506", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00695', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-111-01c5eaab', 'sub-elementary-10ced7e2-05', NULL, 'single_choice', '「在廣大迷茫的世界裡，人要維持本色，安於本色，保有那一點赤子之真，是何等不易？許多時候， 為了某些荒謬的理由，甚至為了某些我們所不能了解的原因，我們便在這浮華匆忙的世界裡迷失了， 被淹沒了，再也找不到以前的自己。精神上的墮落，使我們四顧無依，徬徨迷惑，但在內心深處， 我們依然嚮往一種歸真返璞的清純境界，渴望獲得真正的輕鬆與自由。」 根據上文，下列選項何者最符合作者意旨？', '["繁華落盡見真淳才是我們內心的嚮往", "在浮華世界迷失的人都應該尋求解脫", "保有赤子之心，能讓我們開拓人生視野", "歷經人生的徬徨，方可明白生命的出口"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:47+00:00", "source_pdf_sha1": "6590d4ee65e2", "answer_pdf_sha1": "e24c36da3da8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "506", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00696', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-111-01c5eaab', 'sub-elementary-10ced7e2-05', NULL, 'single_choice', '「我曾是集中營裡的囚犯。我永遠記得，即使在那樣暗無天日的悲慘情況，有人仍是沿著牢房安慰 他人，或是拿出僅剩的麵包分給同伴，也許這些人只是少數，但他們證實了一件事：在某些惡劣的 情況下，人仍有自由選擇自己的處事態度及方式。」 下列選項，何者最接近上文「少數人」的態度？', '["恐懼是人心的惡魔，難以磨滅", "奉獻與分享，是人性中的燦爛", "冷漠的忽視，即是殘忍的默許", "種族雖不同，但非對立的藉口"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:47+00:00", "source_pdf_sha1": "6590d4ee65e2", "answer_pdf_sha1": "e24c36da3da8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "506", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00697', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-111-01c5eaab', 'sub-elementary-10ced7e2-05', NULL, 'single_choice', '「我們的生活不是完全屬於『動態』的，也不完全是屬於『靜態』的，而靜定二字比活動似乎更為 重要。靜不是停滯，靜不是休止，靜是莊嚴的工作、熱切的活動的前奏，好似音樂演奏會啟幕前， 那寂然無嘩的臺前。只有在最深度的寧靜中，你才可以慢慢的調理弦索，時間一到，它才可發出動 人的節響來。只有在幽獨寧靜之中，你才可以悄然的蓄集生命的力量，如涓滴之歸向大海，如塵沙 之堆積邱山，不知不覺間，形成了你的強力與偉大。 上文內容所呈現的情意感受及其意涵，與下列選項何者最貼近？', '["靜觀皆自得", "動靜皆自如", "寧靜以致遠", "情韻靜中求"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:47+00:00", "source_pdf_sha1": "6590d4ee65e2", "answer_pdf_sha1": "e24c36da3da8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "506", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00698', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-111-01c5eaab', 'sub-elementary-10ced7e2-05', NULL, 'single_choice', '「她的冷靜聰明之處在於，即使真看穿了甚麼，也不輕易發人生感慨之語，也不動輒就講佛偈談虛 空，因為這些話術實在太做作也太小聰明，太假清高也太荒謬，她寫作或做人是絕不這麼庸俗圖方 便的，更不會任意消費自己或他人的人生苦痛。這了悟又不覺悟的個性構成她小說中特有的疏離敘 述，也是令人啼笑皆非的黑色幽默的來源。」 根據上文，下列選項何者最貼近文意？', '["強調人有感情，但應該不執著於情", "人活著追求的核心價值是大智若愚", "覺悟很難，不該隨意消費自己或他人的苦痛", "欣賞冷靜聰明的智慧，認同聰明中的荒謬感"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:47+00:00", "source_pdf_sha1": "6590d4ee65e2", "answer_pdf_sha1": "e24c36da3da8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "506", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00699', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-111-01c5eaab', 'sub-elementary-10ced7e2-05', NULL, 'single_choice', '「臺北的家老了，真的成了老家。原本家裡的出入口裝的都是木門，很輕，把手是圓形的金屬，握 上去總是冰涼的，門板的配色很老氣，白色與膚橘色，還貼了許多早已倒閉的連鎖餐廳的招牌貼紙： 大頭黃鳥頂著一頭桃色的羽毛。門板表層的角落，因為老舊與濕氣微微翹起，緩慢露出其下的木頭 紋理。然而，這一切從來不曾讓我感到時光流逝，只是自然地隨時間接受它們的樣貌。」請問本文 的寫作重點是：', '["用細膩的筆觸，委婉地表達家具陳舊的感覺", "運用視覺、聽覺與觸覺強調家真的該裝修了", "用冷靜的敘述方式表達對於時光流逝的無奈", "仔細描寫各樣物件傳達接受家已變老的事實"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:47+00:00", "source_pdf_sha1": "6590d4ee65e2", "answer_pdf_sha1": "e24c36da3da8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "506", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00700', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-111-01c5eaab', 'sub-elementary-10ced7e2-05', NULL, 'single_choice', '「旗津沙灘流失速度愈來愈快，但旗津是觀光島，民眾來到旗津，多半是要到旗津海岸戲水，如果 沒有沙灘，旗津就失去吸引力，所以工程的建立與成敗都具有指標性意義。但以往保護海岸線的方 式，通常是在海岸線放置消波塊，但如此一來，沙灘將不復存在。」 根據上文判斷，作者認為：', '["消波塊不會嚴重破壞旗津沙灘的景觀", "民眾到旗津戲水的雅興不受消波塊影響", "保存沙灘應採放置消波塊之外的新工法", "放置消波塊能真正確保海岸沙灘的完整性"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:47+00:00", "source_pdf_sha1": "6590d4ee65e2", "answer_pdf_sha1": "e24c36da3da8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "506", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL)
